INSERT INTO posts (user_id, content, type, created_at, updated_at) VALUES
(11, 'Chào mọi người, mình là thành viên mới. Mình rất thích đọc tiểu thuyết khoa học viễn tưởng. Có ai có thể gợi ý cho mình vài bộ hay không?', 'FORUM', DATE_SUB(NOW(), INTERVAL 5 DAY), DATE_SUB(NOW(), INTERVAL 5 DAY)),
(7, 'Thể loại tu tiên dạo này có vẻ bão hòa rồi nhỉ? Quanh đi quẩn lại vẫn là motip cũ. Mong chờ một tác phẩm đột phá trên nền tảng!', 'FORUM', DATE_SUB(NOW(), INTERVAL 4 DAY), DATE_SUB(NOW(), INTERVAL 4 DAY)),
(13, 'Các bạn tác giả cho mình hỏi kinh nghiệm xây dựng world-building sao cho logic và hấp dẫn với? Mình đang viết truyện fantasy mà thấy đuối quá.', 'FORUM', DATE_SUB(NOW(), INTERVAL 3 DAY), DATE_SUB(NOW(), INTERVAL 3 DAY)),
(9, 'Review ngắn truyện \"Sự Kiện Bất Thường\": Nội dung ổn, nhân vật nữ chính cá tính. Tuy nhiên kết thúc hơi vội. Điểm: 7.5/10.', 'FORUM', DATE_SUB(NOW(), INTERVAL 2 DAY), DATE_SUB(NOW(), INTERVAL 2 DAY)),
(6, 'Có ai thức đêm chạy deadline chương mới như mình không? Cảm giác gõ phím lạch cạch lúc 2h sáng thật là yomost (và buồn ngủ).', 'FORUM', DATE_SUB(NOW(), INTERVAL 1 DAY), DATE_SUB(NOW(), INTERVAL 1 DAY)),
(12, 'Admin ơi, tính năng thông báo có vẻ hoạt động hơi chậm? Mong đội ngũ kỹ thuật kiểm tra giúp. Cảm ơn ạ!', 'FORUM', DATE_SUB(NOW(), INTERVAL 12 HOUR), DATE_SUB(NOW(), INTERVAL 12 HOUR)),
(9, 'Tuyển beta reader cho truyện ngôn tình ngược tâm! Yêu cầu: đọc kỹ, không ngại góp ý thẳng thắn. Ai quan tâm comment nhé.', 'FORUM', DATE_SUB(NOW(), INTERVAL 10 HOUR), DATE_SUB(NOW(), INTERVAL 10 HOUR)),
(12, 'Mình vừa hoàn thành bộ truyện đầu tay! 150 chương, chặng đường dài nhưng thật tự hào. Cảm ơn các độc giả đã ủng hộ trong suốt 6 tháng qua.', 'FORUM', DATE_SUB(NOW(), INTERVAL 8 HOUR), DATE_SUB(NOW(), INTERVAL 8 HOUR)),
(12, 'Làm sao để thoát khỏi writer block nhỉ? Ngồi nhìn màn hình trắng cả tiếng đồng hồ mà chưa viết được dòng nào. Cứu!!', 'FORUM', DATE_SUB(NOW(), INTERVAL 6 HOUR), DATE_SUB(NOW(), INTERVAL 6 HOUR)),
(4, 'Vừa đọc xong một bộ trinh thám cực đỉnh. Plot twist liên tục khiến não quay cuồng. Mọi người có ai cùng sở thích không, vào bàn luận nào!', 'FORUM', DATE_SUB(NOW(), INTERVAL 4 HOUR), DATE_SUB(NOW(), INTERVAL 4 HOUR)),
(6, 'Khảo sát nhỏ: Các bạn thích nam chính bá đạo tổng tài, hay ôn nhu thâm tình? Mình đang bí ý tưởng cho nam chính của bộ mới.', 'FORUM', DATE_SUB(NOW(), INTERVAL 3 HOUR), DATE_SUB(NOW(), INTERVAL 3 HOUR)),
(11, 'Xin hỏi cách tạo ảnh bìa truyện đẹp mắt mà không cần biết dùng Photoshop? Có tool nào online dễ dùng giới thiệu mình với.', 'FORUM', DATE_SUB(NOW(), INTERVAL 2 HOUR), DATE_SUB(NOW(), INTERVAL 2 HOUR)),
(4, 'Theo mọi người, độ dài mỗi chương khoảng bao nhiêu từ là hợp lý? Mình thường viết 2000 từ nhưng sợ hơi dài khiến độc giả nản.', 'FORUM', DATE_SUB(NOW(), INTERVAL 1 HOUR), DATE_SUB(NOW(), INTERVAL 1 HOUR)),
(4, 'Tranh luận vui: Nên có SE (Sad Ending) hay luôn phải là HE (Happy Ending)? Mình thuộc team thích HE vì cuộc đời đã đủ buồn rồi.', 'FORUM', DATE_SUB(NOW(), INTERVAL 45 MINUTE), DATE_SUB(NOW(), INTERVAL 45 MINUTE)),
(4, 'Chia sẻ mẹo nhỏ cho các tác giả mới: Hãy lập dàn ý chi tiết trước khi viết, sẽ giúp bạn không bị lạc trôi khi cốt truyện ngày càng phức tạp.', 'FORUM', DATE_SUB(NOW(), INTERVAL 30 MINUTE), DATE_SUB(NOW(), INTERVAL 30 MINUTE)),
(6, 'Góc tìm truyện: Nam chính là sát thủ, nữ chính là bác sĩ. Mình quên tên rồi, mong cao nhân giúp đỡ!', 'FORUM', DATE_SUB(NOW(), INTERVAL 20 MINUTE), DATE_SUB(NOW(), INTERVAL 20 MINUTE)),
(10, 'Cộng đồng Abora ngày càng đông vui nhỉ! Mình rất thích không khí ở đây, mọi người hòa đồng và support nhau nhiệt tình.', 'FORUM', DATE_SUB(NOW(), INTERVAL 10 MINUTE), DATE_SUB(NOW(), INTERVAL 10 MINUTE)),
(11, 'Hôm nay trời mưa lãng mạn quá, rất hợp để ngồi gõ một chương truyện buồn. Mọi người đang làm gì thế?', 'FORUM', DATE_SUB(NOW(), INTERVAL 5 MINUTE), DATE_SUB(NOW(), INTERVAL 5 MINUTE)),
(12, 'Xin chào! Có ai biết cách tăng view cho truyện mới không? Mình đăng truyện được 3 ngày rồi mà vẫn lẹt đẹt quá.', 'FORUM', NOW(), NOW());
